Here's an updated `BaseRepository` class in C# that allows you to find by a dynamic field.

```csharp
using System;
using System.Linq;
using Microsoft.EntityFrameworkCore;

public abstract class BaseRepository<T> where T : class
{
    protected readonly DbContext _context;

    protected BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual IQueryable<T> GetAll()
    {
        return _context.Set<T>().AsQueryable();
    }

    public virtual IQueryable<T> GetByDynamicField(string field, object value)
    {
        // Use reflection to get the property info of the field
        var propertyInfo = typeof(T).GetProperty(field);

        if (propertyInfo == null)
        {
            throw new ArgumentException($"Property {field} does not exist in the entity {typeof(T).Name}");
        }

        // Use Expression to create a dynamic lambda expression
        var parameter = Expression.Parameter(typeof(T), "t");
        var member = Expression.MakeMemberAccess(parameter, propertyInfo);
        var constant = Expression.Constant(value);
        var body = Expression.Equal(member, constant);

        var lambda = Expression.Lambda<Func<T, bool>>(body, parameter);

        return _context.Set<T>().Where(lambda);
    }
}
```

